    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "状态：失败")
        Library:Notify({Title="COMBOWICK", Description="会话校验失败。", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ 游戏已禁用")
            safeSet(hintLabel, "此处无法使用免费版，请获取密钥。")
            Library:Notify({Title="COMBOWICK", Description="该游戏已禁用免费版，请使用密钥。", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "状态：失败")
        else
            safeSet(statusLabel, "状态：已验证")
            Library:Notify({Title="COMBOWICK", Description="你已通过验证。", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("剩余时间：%s", fmt))
                    safeSet(lSession, string.format("会话时长：%s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "会话已过期。")
                safeSet(lSession, "会话时长：已过期")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "冷却中")
        safeSet(hintLabel, "获取 11 小时密钥，或等待冷却结束。")
        Library:Notify({Title="COMBOWICK", Description="你正处于冷却中。获取密钥即可跳过等待。", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("冷却时间：%s", fmt))
                safeSet(lCooldown, string.format("冷却时间：%s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "冷却已结束。")
            safeSet(lCooldown, "冷却时间：已结束")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="冷却已结束，正在重新加载…", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "请求过多")
        safeSet(hintLabel, "请求过多，请稍候。")
        Library:Notify({Title="COMBOWICK", Description="请求过多，请稍等片刻。", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("%s 后重试", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "正在重新加载…")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "服务已暂停")
        safeSet(hintLabel, "COMBOWICK 暂时离线。")
        Library:Notify({Title="COMBOWICK", Description="服务当前已禁用，请稍后再试。", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "已封禁")
        Library:Notify({Title="COMBOWICK", Description="你已被封禁。", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 游戏不支持")
        safeSet(hintLabel, "该游戏暂不支持。如有可用脚本，Premium 密钥仍然有效。")
        Library:Notify({Title="COMBOWICK", Description="该游戏暂不支持。", Time=6})

    else
        safeSet(statusLabel, "错误")
        safeSet(hintLabel, "无法连接服务器，请重新运行脚本。")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "发生未知错误。"), Time=5})
    end
end)

